import app from 'flarum/admin/app';
import Modal, { IInternalModalAttrs } from 'flarum/common/components/Modal';
import Button from 'flarum/common/components/Button';
import Stream from 'flarum/common/utils/Stream';

interface RestoreDiscussionModalAttrs extends IInternalModalAttrs {
    discussion: any;
    discussionRestored: Stream<boolean>;
}

export default class RestoreDiscussionModal extends Modal<RestoreDiscussionModalAttrs> {
    discussion: any;
    discussionRestored: Stream<boolean> | undefined; 

    oninit(vnode: any) {
    super.oninit(vnode);
    this.discussion = vnode.attrs.discussion;
    this.discussionRestored = vnode.attrs.discussionRestored;
    }

    className() {
    return 'RestoreDiscussionModal Modal--small';
    }

    title() {
    return app.translator.trans('walsgit-recycle-bin.admin.restore_discussion.title');
    }

    content() {
    return (
        <div className="Modal-body">
        <p>{app.translator.trans('walsgit-recycle-bin.admin.restore_discussion.confirmation')} <strong>{this.discussion.title()}</strong></p>
        <div className="Form Form--centered">
            <div className="Form-group">
            {Button.component(
                {
                type: 'submit',
                className: 'Button Button--primary Button--block',
                loading: this.loading,
                },
                app.translator.trans('walsgit-recycle-bin.admin.restore_discussion.restore_button')
            )}
            </div>
        </div>
        </div>
    );
    }

    onsubmit(e: Event) {
        e.preventDefault();

        this.loading = true;

        this.discussion
            .save({ isHidden: false })
            .then(() => {
                this.hide();
                if (this.discussionRestored) {
                    this.discussionRestored(true);
                }
                m.redraw();
                app.alerts.show(
                    { type: 'success' },
                    app.translator.trans('walsgit-recycle-bin.admin.restore_discussion.success')
                );
            })
            .catch(() => {
                this.loading = false;
                m.redraw();
            });
    }
}
